window.SmartRisk=window.SmartRisk||{};(function(){const routes=new Map(),norm=p=>{const x=String(p||"/").replace(/^#/,"");return x.startsWith("/")?x:`/${x}`},current=()=>norm(location.hash||SmartRisk.Config.defaultRoute);async function resolve(){const p=current(),r=routes.get(p),c=document.getElementById("app-content");SmartRisk.Loader.show("Cargando vista…");try{if(!r){c.innerHTML="<h2>Ruta no encontrada</h2>";return}c.innerHTML=await r.render();SmartRisk.Utils.setTitle(r.title);SmartRisk.Sidebar.setActive(p);SmartRisk.Navbar.update(p);r.bind?.()}finally{SmartRisk.Loader.hide()}}SmartRisk.Router={register(r){routes.set(norm(r.path),r)},start(){addEventListener("hashchange",resolve);if(!location.hash)location.hash=SmartRisk.Config.defaultRoute;else resolve()},current}})();